@page "/book-appointment"
@rendermode InteractiveServer
@using sv_2c0082ab354f4f8785d500c06de23b72.Services
@inject AppointmentService AppointmentSvc

<PageTitle>Book Appointment</PageTitle>

<h3>Book a Medical Appointment</h3>

<EditForm EditContext="editContext" OnValidSubmit="HandleSubmit" FormName="book-appointment">
    <DataAnnotationsValidator />
    <CustomValidator @ref="customValidator" />

    @* ── STEP 1 ── *@
    <fieldset>
        <legend>Patient Information</legend>

        <div class="mb-3">
            <label class="form-label">Patient Name</label>
            <InputText class="form-control" @bind-Value="model.PatientName" />
            <ValidationMessage For="() => model.PatientName" />
        </div>

        <div class="mb-3">
            <label class="form-label">Email</label>
            <InputText class="form-control" @bind-Value="model.Email" />
            <ValidationMessage For="() => model.Email" />
        </div>

        <div class="mb-3">
            <label class="form-label">Phone</label>
            <InputText class="form-control" @bind-Value="model.Phone" />
            <ValidationMessage For="() => model.Phone" />
        </div>

        <div class="mb-3">
            <label class="form-label">Insurance Provider</label>
            <InputSelect class="form-select" @bind-Value="model.InsuranceProvider">
                <option value="">-- Select --</option>
                <option value="Aetna">Aetna</option>
                <option value="BlueCross">BlueCross</option>
                <option value="Cigna">Cigna</option>
                <option value="UnitedHealth">UnitedHealth</option>
                <option value="None">None</option>
            </InputSelect>
            <ValidationMessage For="() => model.InsuranceProvider" />
        </div>

        @if (!showStep2)
        {
            <button type="button" class="btn btn-primary" @onclick="ProceedToStep2">
                Next
            </button>
        }
    </fieldset>

    @* ── STEP 2 ── *@
    @if (showStep2)
    {
        <fieldset class="mt-4">
            <legend>Appointment Details</legend>

            <div class="mb-3">
                <label class="form-label">Preferred Doctor</label>
                <InputSelect class="form-select" @bind-Value="model.Doctor"
                             @bind-Value:after="OnDoctorOrDateChanged">
                    <option value="">-- Select --</option>
                    @foreach (var doc in doctors)
                    {
                        <option value="@doc">@doc</option>
                    }
                </InputSelect>
                <ValidationMessage For="() => model.Doctor" />
            </div>

            <div class="mb-3">
                <label class="form-label">Appointment Date</label>
                <InputDate class="form-control" @bind-Value="model.AppointmentDate"
                           @bind-Value:after="OnDoctorOrDateChanged" />
                <ValidationMessage For="() => model.AppointmentDate" />
            </div>

            <div class="mb-3">
                <label class="form-label">Time Slot</label>
                <InputSelect class="form-select" @bind-Value="model.TimeSlot">
                    <option value="">-- Select --</option>
                    @foreach (var slot in timeSlots)
                    {
                        <option value="@slot">@slot</option>
                    }
                </InputSelect>
                <ValidationMessage For="() => model.TimeSlot" />
            </div>

            <div class="mb-3">
                <label class="form-label">Reason for Visit</label>
                <InputTextArea class="form-control" @bind-Value="model.Reason" rows="3" />
                <ValidationMessage For="() => model.Reason" />
            </div>

            <button type="button" class="btn btn-info me-2" disabled="@isChecking"
                    @onclick="CheckAvailability">
                @(isChecking ? "Checking..." : "Check Availability")
            </button>

            <button type="submit" class="btn btn-success" disabled="@(!availabilityConfirmed || isSubmitting)">
                @(isSubmitting ? "Booking..." : "Book Appointment")
            </button>
        </fieldset>
    }

    @if (bookingConfirmed)
    {
        <div class="alert alert-success mt-3">Appointment booked successfully!</div>
    }
</EditForm>

@code {
    private AppointmentModel model = new();
    private EditContext editContext = null!;
    private CustomValidator? customValidator;

    private List<string> doctors = [];
    private List<string> timeSlots = [];
    private bool showStep2;
    private bool isChecking;
    private bool availabilityConfirmed;
    private bool isSubmitting;
    private bool bookingConfirmed;

    // Fields that belong to step 1
    private static readonly string[] Step1Fields =
        [nameof(AppointmentModel.PatientName), nameof(AppointmentModel.Email),
         nameof(AppointmentModel.Phone), nameof(AppointmentModel.InsuranceProvider)];

    protected override async Task OnInitializedAsync()
    {
        editContext = new EditContext(model);
        doctors = await AppointmentSvc.GetDoctorsAsync();
    }

    private void ProceedToStep2()
    {
        // Validate only step-1 fields
        var isValid = true;
        foreach (var field in Step1Fields)
        {
            var fi = editContext.Field(field);
            editContext.NotifyFieldChanged(fi);
        }

        // Check if any step-1 field has validation messages
        foreach (var field in Step1Fields)
        {
            if (editContext.GetValidationMessages(editContext.Field(field)).Any())
            {
                isValid = false;
            }
        }

        if (isValid)
        {
            showStep2 = true;
        }
    }

    private async Task OnDoctorOrDateChanged()
    {
        availabilityConfirmed = false;
        model.TimeSlot = null;

        if (!string.IsNullOrEmpty(model.Doctor) && model.AppointmentDate.HasValue)
        {
            timeSlots = await AppointmentSvc.GetAvailableTimeSlotsAsync(
                model.Doctor, model.AppointmentDate.Value);
        }
        else
        {
            timeSlots = [];
        }
    }

    private async Task CheckAvailability()
    {
        customValidator?.ClearErrors();
        availabilityConfirmed = false;

        // Validate step 2 fields via data annotations first
        var step2Valid = true;
        string[] step2Fields =
            [nameof(AppointmentModel.Doctor), nameof(AppointmentModel.AppointmentDate),
             nameof(AppointmentModel.TimeSlot), nameof(AppointmentModel.Reason)];

        foreach (var field in step2Fields)
        {
            var fi = editContext.Field(field);
            editContext.NotifyFieldChanged(fi);
            if (editContext.GetValidationMessages(fi).Any())
                step2Valid = false;
        }

        if (!step2Valid) return;

        // Validate date is in the future
        if (model.AppointmentDate.HasValue
            && model.AppointmentDate.Value <= DateOnly.FromDateTime(DateTime.Today))
        {
            customValidator?.DisplayErrors(new Dictionary<string, List<string>>
            {
                [nameof(AppointmentModel.AppointmentDate)] = ["Date must be in the future."]
            });
            return;
        }

        isChecking = true;
        try
        {
            var errors = await AppointmentSvc.ValidatePatientAsync(
                model.Email ?? "",
                model.InsuranceProvider ?? "",
                model.Doctor ?? "",
                model.TimeSlot ?? "");

            if (errors.Count > 0)
            {
                customValidator?.DisplayErrors(errors);
                return;
            }

            availabilityConfirmed = true;
        }
        finally
        {
            isChecking = false;
        }
    }

    private async Task HandleSubmit()
    {
        if (!availabilityConfirmed) return;

        isSubmitting = true;
        try
        {
            // Simulate booking delay
            await Task.Delay(500);
            bookingConfirmed = true;
        }
        finally
        {
            isSubmitting = false;
        }
    }
}

